var isBalanced = function(root) {
    const dfs = (node) => {
        if (node === null) return 0;
        const lh = dfs(node.left);
        if (lh === -1) return -1;
        const rh = dfs(node.right);
        if (rh === -1) return -1;
        if (Math.abs(lh - rh) > 1) return -1;
        return 1 + Math.max(lh, rh);
    };
    return dfs(root) !== -1;
};
